using System.ComponentModel;
using Microsoft.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var researchTools = new ResearchTools();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// ---------------------------------------------------------------------------
// Build the agent
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When the user gives you a topic:
        1. Search the web for relevant information (make 2-3 varied searches).
        2. Save the most important findings as notes using the SaveNote tool.
        3. After collecting enough information, retrieve your notes and write a
           concise summary with key facts and references.
        Always finish by presenting the summary to the user.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings.",
    tools: tools);

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       🔍  Research Agent  (AI)          ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync($"research-{Guid.NewGuid():N}");

await foreach (var update in agent.RunStreamingAsync($"Research the following topic and provide a summary: {topic}", session))
{
    foreach (var content in update.Contents)
    {
        if (content is TextContent text)
        {
            Console.Write(text.Text);
        }
        else if (content is FunctionCallContent fc)
        {
            Console.ForegroundColor = ConsoleColor.DarkCyan;
            Console.Write($"\n  🔧 Calling {fc.Name}...");
            Console.ResetColor();
        }
        else if (content is FunctionResultContent fr)
        {
            Console.ForegroundColor = ConsoleColor.DarkGreen;
            var preview = fr.Result?.ToString() ?? "";
            if (preview.Length > 120) preview = preview[..120] + "…";
            Console.WriteLine($"  ✅ {preview}");
            Console.ResetColor();
        }
    }
}

Console.WriteLine("\n\nDone.");

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Provides web-search and note-taking tools for the research agent.</summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();

    [Description("Search the web for a given query and return relevant result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        // Use the DuckDuckGo instant-answer API (no key required).
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await _http.GetStringAsync(url);
            // Return the raw JSON; the model will extract what it needs.
            if (json.Length > 4000) json = json[..4000];
            return json;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important findings.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes saved yet.";
        return string.Join("\n\n", _notes.Select((n, i) => $"[Note {i + 1}] {n}"));
    }
}

